SET client_min_messages TO warning;

ALTER TABLE public.pages
  ALTER COLUMN tenant_id DROP NOT NULL;

ALTER TABLE public.menus
  ALTER COLUMN tenant_id DROP NOT NULL;

DO $$
DECLARE
  v_owner_id uuid;
BEGIN
  SELECT u.id
  INTO v_owner_id
  FROM public.users u
  LEFT JOIN public.roles r ON r.id = u.role_id
  WHERE u.deleted_at IS NULL
    AND (r.is_platform_admin = true OR r.is_full_access = true OR r.scope = 'platform')
  ORDER BY u.created_at ASC
  LIMIT 1;

  WITH platform_pages(slug, title_id, title_en, excerpt_id, excerpt_en, content_id, content_en, meta_description_id, meta_description_en) AS (
    VALUES
      ('terms','Syarat dan Ketentuan','Terms & Conditions','Ketentuan penggunaan layanan dan tanggung jawab para pihak dalam ekosistem AhliWeb.','Service usage terms and responsibilities for all parties in the AhliWeb ecosystem.',$terms_id$<p>Halaman ini mengatur penggunaan layanan digital AhliWeb, termasuk pengembangan web, aplikasi, otomasi bisnis, cloud, keamanan siber, dan konsultasi. Dengan menggunakan layanan kami, Anda setuju untuk menjalankan kerja sama secara jujur, profesional, dan tidak bertentangan dengan syariat Islam berdasarkan Al-Qur'an dan As-Sunnah sesuai pemahaman Salafus Shalih.</p><h2>Ruang Lingkup Layanan</h2><ul><li>Layanan mencakup pekerjaan yang disepakati dalam proposal, kontrak, atau purchase order yang sah.</li><li>Perubahan ruang lingkup, revisi besar, atau tambahan integrasi diproses melalui persetujuan tertulis.</li><li>Kami berhak menolak permintaan yang melanggar hukum, merugikan pihak lain, mengandung unsur maksiat, gharar berlebihan, riba, judi, pornografi, atau propaganda yang bertentangan dengan prinsip Ahlussunnah wal Jama'ah.</li></ul><h2>Kewajiban Pengguna</h2><ul><li>Memberikan data, akses, dan materi yang benar serta memiliki hak penggunaan yang sah.</li><li>Menjaga kerahasiaan akun admin, API key, dan kredensial lainnya.</li><li>Tidak menggunakan hasil kerja AhliWeb untuk aktivitas yang melanggar hukum, etika, atau syariat.</li></ul><h2>Pembayaran dan Penyelesaian Pekerjaan</h2><ul><li>Skema pembayaran mengikuti akad yang disepakati dan harus bebas dari unsur manipulatif.</li><li>Keterlambatan dari pihak klien dalam memberikan materi atau persetujuan dapat memengaruhi timeline.</li><li>Serah terima dilakukan setelah lingkup pekerjaan yang disepakati terpenuhi.</li></ul><h2>Batasan Tanggung Jawab</h2><p>Kami berkomitmen memberikan ikhtiar terbaik, tetapi tidak bertanggung jawab atas kerugian akibat perubahan regulasi, gangguan pihak ketiga, atau penggunaan sistem di luar panduan yang kami berikan. Sengketa diselesaikan terlebih dahulu melalui musyawarah yang adil.</p>$terms_id$,$terms_en$<p>This page governs the use of AhliWeb digital services, including web and app development, business automation, cloud, cybersecurity, and consulting. By using our services, you agree to uphold honesty, professionalism, and conduct that does not contradict Islamic principles based on the Qur'an and Sunnah according to the understanding of the Salafus Shalih.</p><h2>Service Scope</h2><ul><li>Services cover the deliverables agreed in a valid proposal, contract, or purchase order.</li><li>Scope changes, major revisions, or additional integrations require written approval.</li><li>We may reject requests that violate the law, harm others, or include usury, gambling, pornography, unlawful propaganda, or anything contrary to Ahlussunnah wal Jama'ah principles.</li></ul><h2>User Responsibilities</h2><ul><li>Provide accurate data, lawful access, and materials you are authorized to use.</li><li>Protect admin accounts, API keys, and all other credentials.</li><li>Do not use AhliWeb deliverables for unlawful, unethical, or non-sharia compliant activities.</li></ul><h2>Payment and Delivery</h2><ul><li>Payment terms follow the agreed contract and must remain free from manipulative practices.</li><li>Delays in approvals or client-provided materials may impact the delivery timeline.</li><li>Handover takes place after the agreed scope has been fulfilled.</li></ul><h2>Limitation of Liability</h2><p>We strive to provide our best effort, but we are not responsible for losses caused by regulatory changes, third-party disruptions, or use of the system outside the guidance we provide. Any dispute should first be resolved through fair consultation and mutual agreement.</p>$terms_en$,'Ketentuan umum layanan AhliWeb yang berlandaskan profesionalitas, kepatuhan hukum, dan nilai syariah.','General AhliWeb service terms grounded in professionalism, lawful conduct, and sharia values.'),
      ('privacy','Kebijakan Privasi','Privacy Policy','Penjelasan mengenai pengumpulan, penggunaan, penyimpanan, dan perlindungan data oleh AhliWeb.','How AhliWeb collects, uses, stores, and protects personal and operational data.',$privacy_id$<p>AhliWeb menghormati amanah data yang dipercayakan oleh pelanggan, calon pelanggan, dan pengunjung situs. Kami hanya mengumpulkan data yang relevan untuk komunikasi, pelayanan, pengembangan produk, dan pemenuhan kewajiban hukum yang sah.</p><h2>Data yang Dikelola</h2><ul><li>Identitas dasar seperti nama, email, nomor telepon, perusahaan, dan kebutuhan proyek.</li><li>Data teknis seperti log akses, alamat IP, perangkat, dan performa layanan untuk tujuan keamanan dan audit.</li><li>Dokumen proyek, aset digital, atau data operasional yang secara sah diserahkan untuk pelaksanaan layanan.</li></ul><h2>Penggunaan Data</h2><ul><li>Memproses permintaan konsultasi, penawaran, implementasi, support, dan penagihan.</li><li>Meningkatkan mutu layanan, keamanan sistem, dan pengalaman pengguna.</li><li>Memenuhi kewajiban kepatuhan, audit, dan investigasi insiden jika diperlukan.</li></ul><h2>Perlindungan Data</h2><p>Kami menerapkan kontrol akses, audit log, segmentasi tenant, RLS, backup, dan pengamanan infrastruktur secara proporsional. Kami tidak menjual data pelanggan dan hanya membagikannya kepada pihak yang relevan untuk pelaksanaan layanan yang sah.</p><h2>Hak Pengguna</h2><p>Pengguna dapat meminta koreksi, pembaruan, atau penghapusan data sepanjang tidak bertentangan dengan kewajiban kontrak, hukum, atau kebutuhan audit keamanan.</p>$privacy_id$,$privacy_en$<p>AhliWeb respects the trust placed in us by customers, prospects, and site visitors. We only collect data that is relevant to communication, service delivery, product improvement, and lawful compliance obligations.</p><h2>Data We Process</h2><ul><li>Basic identity data such as name, email, phone number, company, and project requirements.</li><li>Technical data such as access logs, IP address, device information, and service performance for security and audit purposes.</li><li>Project documents, digital assets, or operational data lawfully provided for service execution.</li></ul><h2>How Data Is Used</h2><ul><li>To process consultations, proposals, implementation, support, and billing.</li><li>To improve service quality, system security, and user experience.</li><li>To fulfill lawful compliance, audit, and incident-response obligations when required.</li></ul><h2>Data Protection</h2><p>We apply proportional access controls, audit logging, tenant segmentation, RLS, backups, and infrastructure security. We do not sell customer data and only share it with relevant parties for legitimate service delivery.</p><h2>User Rights</h2><p>Users may request correction, updates, or deletion of data to the extent that such requests do not conflict with contractual duties, legal obligations, or security-audit requirements.</p>$privacy_en$,'Kebijakan privasi AhliWeb tentang amanah data, keamanan, dan hak pengguna.','AhliWeb privacy policy covering data trust, security, and user rights.'),
      ('licensing','Lisensi','Licensing','Ketentuan lisensi penggunaan hasil kerja, source code, aset desain, dan layanan AhliWeb.','Licensing terms for deliverables, source code, design assets, and managed services provided by AhliWeb.',$licensing_id$<p>Lisensi atas hasil kerja AhliWeb diberikan sesuai akad, lingkup proyek, dan jenis layanan. Hak penggunaan tidak otomatis berarti perpindahan penuh atas seluruh komponen, terutama jika terdapat library pihak ketiga, lisensi open-source, template berbayar, atau modul internal AhliWeb.</p><h2>Hak Penggunaan Standar</h2><ul><li>Klien memperoleh hak menggunakan deliverable sesuai tujuan bisnis yang disepakati.</li><li>Hak eksklusif, lisensi ulang, atau pemindahan hak cipta harus disebutkan secara tertulis dalam kontrak.</li><li>Komponen open-source tetap mengikuti lisensi asli masing-masing.</li></ul><h2>Kepatuhan Lisensi</h2><ul><li>Klien wajib menjaga atribusi, notice lisensi, dan pembatasan lisensi pihak ketiga bila berlaku.</li><li>Dilarang mendistribusikan ulang komponen yang tidak termasuk dalam hak penggunaan yang diberikan.</li><li>Penggunaan aset harus tetap selaras dengan hukum, etika, dan prinsip syariah.</li></ul><h2>Layanan Berlangganan</h2><p>Untuk layanan managed service, hosting, automasi, atau dashboard, hak penggunaan berlangsung selama masa layanan aktif kecuali ditentukan lain secara tertulis.</p>$licensing_id$,$licensing_en$<p>Licensing for AhliWeb deliverables is governed by the contract, project scope, and service type. A right to use does not automatically transfer full ownership of every component, especially where third-party libraries, open-source licenses, paid templates, or AhliWeb internal modules are involved.</p><h2>Standard Usage Rights</h2><ul><li>The client receives the right to use the deliverables for the agreed business purpose.</li><li>Exclusive rights, sublicensing, or copyright transfer must be explicitly stated in writing.</li><li>Open-source components remain subject to their original licenses.</li></ul><h2>License Compliance</h2><ul><li>Clients must preserve attribution, license notices, and any third-party restrictions where required.</li><li>Redistribution of components outside the granted usage rights is prohibited.</li><li>All use must remain consistent with law, ethics, and sharia-compliant principles.</li></ul><h2>Subscription Services</h2><p>For managed services, hosting, automation, or dashboard subscriptions, usage rights continue for the active service period unless otherwise stated in writing.</p>$licensing_en$,'Ketentuan lisensi AhliWeb untuk source code, aset desain, dan deliverable layanan.','AhliWeb licensing terms for source code, design assets, and service deliverables.'),
      ('cookie-policy','Kebijakan Cookie','Cookie Policy','Penjelasan penggunaan cookie dan teknologi serupa untuk keamanan, analitik, dan pengalaman pengguna.','How cookies and similar technologies are used for security, analytics, and user experience.',$cookie_id$<p>Situs dan aplikasi AhliWeb dapat menggunakan cookie atau teknologi serupa untuk menjaga sesi, mengukur performa, meningkatkan keamanan, dan memahami penggunaan layanan secara agregat.</p><h2>Jenis Cookie</h2><ul><li>Cookie esensial untuk autentikasi, keamanan, dan preferensi dasar.</li><li>Cookie analitik untuk memahami perilaku penggunaan secara umum tanpa tujuan yang merugikan pengguna.</li><li>Cookie fungsional untuk meningkatkan pengalaman navigasi dan personalisasi yang wajar.</li></ul><h2>Pilihan Pengguna</h2><p>Pengguna dapat mengatur preferensi cookie melalui browser atau banner persetujuan jika tersedia. Menonaktifkan cookie tertentu dapat memengaruhi fungsi situs atau aplikasi.</p><h2>Kebijakan Penggunaan</h2><p>Kami tidak menggunakan cookie untuk tujuan yang melanggar privasi, manipulatif, atau bertentangan dengan prinsip transparansi dan amanah.</p>$cookie_id$,$cookie_en$<p>AhliWeb websites and applications may use cookies or similar technologies to preserve sessions, measure performance, improve security, and understand service usage in the aggregate.</p><h2>Cookie Categories</h2><ul><li>Essential cookies for authentication, security, and baseline preferences.</li><li>Analytics cookies to understand general usage behavior without harming user privacy.</li><li>Functional cookies to improve navigation and reasonable personalization.</li></ul><h2>User Choices</h2><p>Users may control cookie preferences through browser settings or a consent banner where provided. Disabling certain cookies may affect parts of the site or application.</p><h2>Usage Principles</h2><p>We do not use cookies for manipulative purposes or in ways that contradict transparency, trust, and responsible stewardship.</p>$cookie_en$,'Kebijakan cookie AhliWeb untuk keamanan, preferensi, dan analitik yang transparan.','AhliWeb cookie policy for transparent security, preferences, and analytics use.'),
      ('contact','Kontak','Contact','Informasi kontak resmi AhliWeb untuk konsultasi, kerja sama, dan layanan dukungan.','Official AhliWeb contact information for consultations, collaboration, and support.',$contact_id$<p>AhliWeb siap membantu kebutuhan transformasi digital, pengembangan aplikasi, automasi bisnis, infrastruktur cloud, dan layanan konsultasi yang sesuai dengan nilai syariah.</p><h2>Kantor dan Kanal Resmi</h2><ul><li>PT Ahli Web Internasional</li><li>Jl. Sutan Syahrir Gg. Lombok 1, RT.003, Arut Selatan, Pangkalan Bun, Kalimantan Tengah 74112 Indonesia</li><li>WhatsApp: +62-895-1338-0400</li><li>Email: info@ahliweb.com dan halo@ahliweb.com</li><li>Website: https://ahliweb.co.id</li></ul><h2>Jam Respons</h2><p>Tim kami berusaha merespons pertanyaan bisnis dan dukungan secepat mungkin. Untuk isu operasional penting, gunakan kanal resmi yang telah disepakati dalam kontrak atau SLA.</p>$contact_id$,$contact_en$<p>AhliWeb is ready to support digital transformation, application development, business automation, cloud infrastructure, and consulting services aligned with sharia values.</p><h2>Head Office and Official Channels</h2><ul><li>PT Ahli Web Internasional</li><li>Jl. Sutan Syahrir Gg. Lombok 1, RT.003, Arut Selatan, Pangkalan Bun, Kalimantan Tengah 74112 Indonesia</li><li>WhatsApp: +62-895-1338-0400</li><li>Email: info@ahliweb.com and halo@ahliweb.com</li><li>Website: https://ahliweb.co.id</li></ul><h2>Response Time</h2><p>Our team aims to respond to business and support inquiries promptly. For important operational issues, please use the official channels agreed in your contract or SLA.</p>$contact_en$,'Informasi kontak resmi AhliWeb untuk konsultasi, kolaborasi, dan dukungan.','Official AhliWeb contact information for consultation, collaboration, and support.')
  ),
  inserted_pages AS (
    INSERT INTO public.pages (tenant_id,title,slug,content,excerpt,meta_title,meta_description,status,workflow_state,is_active,is_public,editor_type,page_type,created_by,created_at,updated_at,published_at)
    SELECT NULL,page.title_id,page.slug,page.content_id,page.excerpt_id,page.title_en,page.meta_description_id,'published','published',true,true,'richtext','regular',v_owner_id,now(),now(),now()
    FROM platform_pages page
    WHERE NOT EXISTS (
      SELECT 1 FROM public.pages existing WHERE existing.tenant_id IS NULL AND existing.slug = page.slug AND existing.deleted_at IS NULL
    )
    RETURNING id, slug
  )
  INSERT INTO public.content_translations (content_type,content_id,locale,title,slug,content,excerpt,meta_description,tenant_id,created_at,updated_at)
  SELECT 'page',p.id,'en',seed.title_en,seed.slug,seed.content_en,seed.excerpt_en,seed.meta_description_en,NULL,now(),now()
  FROM platform_pages seed
  JOIN public.pages p ON p.tenant_id IS NULL AND p.slug = seed.slug AND p.deleted_at IS NULL
  WHERE NOT EXISTS (
    SELECT 1 FROM public.content_translations existing WHERE existing.tenant_id IS NULL AND existing.content_type = 'page' AND existing.content_id = p.id AND existing.locale = 'en'
  );

  INSERT INTO public.menus (tenant_id,name,label,slug,url,parent_id,"order",is_active,is_public,group_label,location,locale,created_by,created_at,updated_at)
  SELECT NULL,root.name,root.label,root.slug,NULL,NULL,root.sort_order,true,true,'footer','footer',root.locale,v_owner_id,now(),now()
  FROM (
    VALUES
      ('footer_legal_id', 'Legal', 'footer-legal-id', 900, 'id'),
      ('footer_legal_en', 'Legal', 'footer-legal-en', 900, 'en'),
      ('footer_company_id', 'Perusahaan', 'footer-company-id', 950, 'id'),
      ('footer_company_en', 'Company', 'footer-company-en', 950, 'en')
  ) AS root(name, label, slug, sort_order, locale)
  WHERE NOT EXISTS (
    SELECT 1 FROM public.menus existing WHERE existing.tenant_id IS NULL AND existing.name = root.name AND existing.location = 'footer' AND existing.locale = root.locale AND existing.deleted_at IS NULL
  );

  INSERT INTO public.menus (tenant_id,name,label,slug,url,parent_id,"order",is_active,is_public,group_label,location,locale,created_by,created_at,updated_at)
  SELECT NULL,child.name,child.label,child.slug,child.url,parent.id,child.sort_order,true,true,'footer','footer',child.locale,v_owner_id,now(),now()
  FROM (
    VALUES
      ('footer_terms_id', 'Syarat & Ketentuan', 'footer-terms-id', '/id/p/terms', 'footer_legal_id', 910, 'id'),
      ('footer_privacy_id', 'Kebijakan Privasi', 'footer-privacy-id', '/id/p/privacy', 'footer_legal_id', 920, 'id'),
      ('footer_licensing_id', 'Lisensi', 'footer-licensing-id', '/id/p/licensing', 'footer_legal_id', 930, 'id'),
      ('footer_cookie_id', 'Kebijakan Cookie', 'footer-cookie-id', '/id/p/cookie-policy', 'footer_legal_id', 940, 'id'),
      ('footer_contact_id', 'Kontak', 'footer-contact-id', '/id/p/contact', 'footer_company_id', 960, 'id'),
      ('footer_terms_en', 'Terms & Conditions', 'footer-terms-en', '/en/p/terms', 'footer_legal_en', 910, 'en'),
      ('footer_privacy_en', 'Privacy Policy', 'footer-privacy-en', '/en/p/privacy', 'footer_legal_en', 920, 'en'),
      ('footer_licensing_en', 'Licensing', 'footer-licensing-en', '/en/p/licensing', 'footer_legal_en', 930, 'en'),
      ('footer_cookie_en', 'Cookie Policy', 'footer-cookie-en', '/en/p/cookie-policy', 'footer_legal_en', 940, 'en'),
      ('footer_contact_en', 'Contact', 'footer-contact-en', '/en/p/contact', 'footer_company_en', 960, 'en')
  ) AS child(name, label, slug, url, parent_name, sort_order, locale)
  JOIN public.menus parent ON parent.tenant_id IS NULL AND parent.name = child.parent_name AND parent.location = 'footer' AND parent.locale = child.locale AND parent.deleted_at IS NULL
  WHERE NOT EXISTS (
    SELECT 1 FROM public.menus existing WHERE existing.tenant_id IS NULL AND existing.name = child.name AND existing.location = 'footer' AND existing.locale = child.locale AND existing.deleted_at IS NULL
  );
END $$;
